from .style import ZORDER, SKY_COLOR"""--------------------------------------------------------------------------------------------------- Low-level drawing functions for atmospheric transmission and sky radiance ------------------------------------------------------------------------------------------------------"""def _draw_sky(    sky,    ax,    sky_mode="transmission",):    """    Draw a Sky model.    Parameters    ----------    sky : Sky        Sky model to display.    ax : matplotlib.axes.Axes        Axis on which to draw.    sky_mode : {"transmission", "radiance"}, optional        Sky quantity to plot.    Returns    -------    matplotlib.axes.Axes        The modified axes.    """    if sky_mode == "transmission":        y = sky.transmission    elif sky_mode == "radiance":        # Convert to Gph s⁻¹ m⁻² μm⁻¹ arcsec⁻² for plotting.        y = sky.radiance / 1e9    else:        raise ValueError(            "sky_mode must be 'transmission' or 'radiance'."        )    ax.plot(        sky.wavelength,        y,        color=SKY_COLOR[sky_mode],        lw=0.3,        zorder=ZORDER["sky"],        label=sky_mode    )        return ax        